async function main() {
  const app = initializeApp(firebaseConfig);
  const auth = getAuth(app);
  const db = getFirestore(app);
  try { await signInWithEmailAndPassword(auth, 'eliteemporium112024@gmail.com', '99445281SL'); console.log('Signed in'); } catch(e) { console.log('Auth skipped'); }

  const snap = await getDocs(collection(db, 'products'));
  let updated = 0, skipped = 0, failed = 0;

  for (const d of snap.docs) {
    const docId = d.id;
    const desc = DESCRIPTIONS[docId];
    if (!desc) { skipped++; continue; }
    try {
      await updateDoc(doc(db, 'products', docId), { desc });
      console.log('UPDATED', docId, d.data().name);
      updated++;
    } catch(e) {
      console.error('FAIL', docId, e.message);
      failed++;
    }
  }

  console.log(`\nDone: updated=${updated} skipped=${skipped} failed=${failed}`);
  process.exit(0);
}

main().catch(e => { console.error(e); process.exit(1); });
